var userConnection = Get<UserConnection>("UserConnection");

string stringParam = Get<string>("StringParam");
Guid submissionId = Get<Guid>("SubmissionId");
Guid lineDetailId = Get<Guid>("LineDetailId");

try {
	var calculateTaxFee = new CalculateTaxFeeService(userConnection);

	if(!string.IsNullOrEmpty(stringParam) && submissionId == Guid.Empty && lineDetailId == Guid.Empty) {
		
		calculateTaxFee
			.SetParam(HTTPRequest.XmlToObject<CalculateTaxFeeRequest.Envelope>(stringParam))
			.Request()
			.GetAwaiter()
			.GetResult();

		Set("Response", calculateTaxFee.GetStringResponse());
		Set("Request", stringParam);
		
	} else if(string.IsNullOrEmpty(stringParam) && submissionId == Guid.Empty && lineDetailId != Guid.Empty) {
		
		calculateTaxFee
			.SetParam("DgLineDetail", lineDetailId)
			.Request()
			.GetAwaiter()
			.GetResult();

		Set("Response", string.Join("\n\n", calculateTaxFee.GetStringBatchResponse()));
		Set("Request", string.Join("\n\n", calculateTaxFee.GetStringParam()));
		
	} else if(string.IsNullOrEmpty(stringParam) && submissionId != Guid.Empty && lineDetailId == Guid.Empty) {
		
		calculateTaxFee
			.SetParam("DgSubmission", submissionId)
			.Request()
			.GetAwaiter()
			.GetResult();
			
		Set("Response", string.Join("\n\n", calculateTaxFee.GetStringBatchResponse()));
		Set("Request", string.Join("\n\n", calculateTaxFee.GetStringParam()));

	} else {
		throw new Exception("Param / Submission / Line Detail harus diisi salah satunya");
	}
} catch(Exception e) {
	Set("Message", e.Message);	
}

return true;
